#ifndef _CUDA_UTILS_H
#define _CUDA_UTILS_H

#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>
#include <cmath>

#ifdef __HIP_PLATFORM_AMD__
#include <hip/hip_runtime.h>
#else
#include <cuda.h>
#include <cuda_runtime.h>
#endif

#include <algorithm>
#include <vector>

#define TOTAL_THREADS 512

inline int opt_n_threads(int work_size) {
  const int pow_2 = std::log(static_cast<double>(work_size)) / std::log(2.0);

  return std::max(std::min(1 << pow_2, TOTAL_THREADS), 1);
}

inline dim3 opt_block_config(int x, int y) {
  const int x_threads = opt_n_threads(x);
  const int y_threads =
      std::max(std::min(opt_n_threads(y), TOTAL_THREADS / x_threads), 1);
  dim3 block_config(x_threads, y_threads, 1);

  return block_config;
}

#ifdef __HIP_PLATFORM_AMD__
#define CUDA_CHECK_ERRORS()                                                \
  do {                                                                     \
    hipError_t err = hipGetLastError();                                     \
    if (hipSuccess != err) {                                               \
      fprintf(stderr, "HIP kernel failed : %s\n%s at L:%d in %s\n",       \
              hipGetErrorString(err), __PRETTY_FUNCTION__, __LINE__,       \
              __FILE__);                                                   \
      exit(-1);                                                            \
    }                                                                      \
  } while (0)
#else
#define CUDA_CHECK_ERRORS()                                               \
  do {                                                                    \
    cudaError_t err = cudaGetLastError();                                  \
    if (cudaSuccess != err) {                                             \
      fprintf(stderr, "CUDA kernel failed : %s\n%s at L:%d in %s\n",     \
              cudaGetErrorString(err), __PRETTY_FUNCTION__, __LINE__,     \
              __FILE__);                                                  \
      exit(-1);                                                           \
    }                                                                     \
  } while (0)
#endif

#endif

